#include <stdio.h>
#include <stdbool.h>

bool isSubsetSum(int n, int arr[], int target) {
    bool dp[target + 1];
    dp[0] = true;
    for (int i = 1; i <= target; ++i) dp[i] = false;
    for (int i = 0; i < n; ++i) {
        int val = arr[i];
        for (int s = target; s >= val; --s) {
            if (dp[s - val]) dp[s] = true;
        }
    }
    return dp[target];
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n, target; scanf("%d %d", &n, &target);
        int arr[100];
        for (int i = 0; i < n; ++i) scanf("%d", &arr[i]);
        printf("%s\n", isSubsetSum(n, arr, target) ? "true" : "false");
    }
    return 0;
}

